import React, { useState, useEffect, useRef, useCallback } from 'react';
import { AreaChart, Area, LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { Play, Pause, RotateCcw, Edit2, TrendingUp, TrendingDown, AlertTriangle, Wifi, Activity, Search, X, ChevronUp, ChevronDown } from 'lucide-react';

const API_BASE = 'https://macondo.hackclub.com/api/projects';

function useBlink(active, interval = 600) {
  const [visible, setVisible] = useState(true);
  useEffect(() => {
    if (!active) { setVisible(true); return; }
    const id = setInterval(() => setVisible(v => !v), interval);
    return () => clearInterval(id);
  }, [active, interval]);
  return visible;
}

export default function IncomeMonitor() {
  const [isRunning, setIsRunning] = useState(false);
  const [elapsedSeconds, setElapsedSeconds] = useState(0);
  const [liveChart, setLiveChart] = useState([]);
  const [sessions, setSessions] = useState([]);
  const [formula, setFormula] = useState('7 * 0.01 * streak');
  const [streak, setStreak] = useState(1);
  const [showFormulaEditor, setShowFormulaEditor] = useState(false);
  const [showProjectPanel, setShowProjectPanel] = useState(false);
  const [projectIdInput, setProjectIdInput] = useState('');
  const [project, setProject] = useState(null);
  const [projectError, setProjectError] = useState('');
  const [projectLoading, setProjectLoading] = useState(false);
  const [tick, setTick] = useState(0);
  const timerRef = useRef(null);
  const autoSaveRef = useRef(null);

  useEffect(() => {
    const saved = localStorage.getItem('im_v2');
    if (saved) {
      try {
        const d = JSON.parse(saved);
        setSessions(d.sessions || []);
        setFormula(d.formula || '7 * 0.01 * streak');
        setStreak(d.streak || 1);
        if (d.project) setProject(d.project);
        if (d.liveChart) setLiveChart(d.liveChart.slice(-60));
      } catch {}
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('im_v2', JSON.stringify({ sessions, formula, streak, project, liveChart: liveChart.slice(-120) }));
  }, [sessions, formula, streak, project, liveChart]);

  useEffect(() => {
    if (isRunning) {
      timerRef.current = setInterval(() => {
        setElapsedSeconds(prev => prev + 1);
        setTick(t => t + 1);
      }, 1000);
    } else {
      clearInterval(timerRef.current);
    }
    return () => clearInterval(timerRef.current);
  }, [isRunning]);

  const effectiveStreak = project ? project.project_streak_days / 10 : streak;

  const calculateIncome = useCallback((seconds) => {
    const hours = seconds / 3600;
    try {
      const rate = eval(formula.replace('streak', effectiveStreak));
      return rate * hours;
    } catch {
      return 7 * hours * 0.01 * effectiveStreak;
    }
  }, [formula, effectiveStreak]);

  useEffect(() => {
    if (!isRunning) return;
    const income = calculateIncome(elapsedSeconds);
    const now = new Date();
    setLiveChart(prev => {
      const point = {
        t: now.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }),
        income: parseFloat(income.toFixed(4)),
        rate: elapsedSeconds > 0 ? parseFloat((income / (elapsedSeconds / 3600)).toFixed(4)) : 0,
      };
      return [...prev.slice(-119), point];
    });
  }, [tick]);

  const currentIncome = calculateIncome(elapsedSeconds);
  const hoursElapsed = elapsedSeconds / 3600;
  const incomePerHour = hoursElapsed > 0 ? currentIncome / hoursElapsed : 0;

  const avgProductivity = sessions.filter(s => !s.manual).length > 0
    ? sessions.filter(s => !s.manual).reduce((sum, s) => sum + s.incomePerHour, 0) / sessions.filter(s => !s.manual).length
    : 7 * 0.01 * effectiveStreak;

  const isHigh = isRunning ? incomePerHour >= avgProductivity * 0.9 : false;
  const isLow = isRunning && !isHigh;
  const alertBlink = useBlink(isLow, 500);

  const prevIncome = liveChart.length >= 2 ? liveChart[liveChart.length - 2]?.income : 0;
  const incomeChange = liveChart.length >= 2 ? currentIncome - prevIncome : 0;

  const handleStop = () => {
    setIsRunning(false);
    if (elapsedSeconds > 0) {
      const newSession = {
        id: Date.now(),
        duration: elapsedSeconds,
        income: currentIncome,
        incomePerHour,
        timestamp: new Date().toLocaleDateString(),
        time: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
        streak: effectiveStreak,
        projectName: project?.name || null,
      };
      setSessions(prev => [...prev, newSession]);
      setStreak(s => s + 0.1);
    }
    setElapsedSeconds(0);
  };

  const handleReset = () => {
    setIsRunning(false);
    setElapsedSeconds(0);
    setLiveChart([]);
  };

  const handleFetchProject = async () => {
    const id = projectIdInput.trim();
    if (!id) return;
    setProjectLoading(true);
    setProjectError('');
    try {
      const res = await fetch(`${API_BASE}/${id}`);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data = await res.json();
      setProject(data);
      setShowProjectPanel(false);
      setProjectIdInput('');
    } catch (e) {
      setProjectError(`Failed to load project: ${e.message}`);
    } finally {
      setProjectLoading(false);
    }
  };

  const formatTime = (seconds) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}:${String(s).padStart(2, '0')}`;
  };

  const totalIncome = sessions.reduce((sum, s) => sum + s.income, 0);
  const todayIncome = sessions
    .filter(s => s.timestamp === new Date().toLocaleDateString())
    .reduce((sum, s) => sum + s.income, 0);

  const totalJournalHours = project?.journals?.reduce((sum, j) => sum + (j.hours || 0), 0) || 0;

  return (
    <div className="w-full min-h-screen bg-[#060b18] text-white font-mono relative overflow-hidden">
      {/* Scan-line overlay */}
      <div className="pointer-events-none absolute inset-0 z-0"
        style={{ background: 'repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(0,0,0,0.07) 2px, rgba(0,0,0,0.07) 4px)' }} />

      {/* LOW ALERT Banner */}
      {isLow && (
        <div className={`fixed top-0 left-0 right-0 z-50 flex items-center justify-center gap-3 py-2 transition-opacity duration-200 ${alertBlink ? 'opacity-100' : 'opacity-0'}`}
          style={{ background: 'linear-gradient(90deg,#ff003322,#ff003388,#ff003322)', borderBottom: '1px solid #ff0033' }}>
          <AlertTriangle size={16} className="text-[#ff0033]" />
          <span className="text-[#ff0033] text-xs tracking-[0.3em] font-bold">⚠ LOW PRODUCTIVITY ALERT — BELOW AVERAGE RATE</span>
          <AlertTriangle size={16} className="text-[#ff0033]" />
        </div>
      )}

      {/* Top Ticker Bar */}
      <div className="relative z-10 border-b border-[#1a2540] bg-[#080d1a] px-6 py-2 flex items-center justify-between gap-4 overflow-hidden">
        <div className="flex items-center gap-6">
          <span className="text-[#00ff88] text-xs tracking-[0.3em]">INCOME/MONITOR</span>
          <div className="flex items-center gap-1">
            <div className={`w-2 h-2 rounded-full ${isRunning ? 'bg-[#00ff88] animate-pulse' : 'bg-[#444]'}`} />
            <span className="text-[10px] text-[#666]">{isRunning ? 'LIVE' : 'IDLE'}</span>
          </div>
        </div>
        <div className="flex items-center gap-8 text-[11px]">
          <TickerItem label="SESSION" value={`$${currentIncome.toFixed(4)}`} change={incomeChange} />
          <TickerItem label="RATE/HR" value={`$${incomePerHour.toFixed(3)}`} neutral />
          <TickerItem label="TODAY" value={`$${todayIncome.toFixed(2)}`} neutral />
          <TickerItem label="TOTAL" value={`$${totalIncome.toFixed(2)}`} neutral />
          <TickerItem label="STREAK" value={`${effectiveStreak.toFixed(1)}x`} neutral />
        </div>
        <div className="flex items-center gap-2 text-[10px] text-[#444]">
          <Wifi size={12} />
          <span>{new Date().toLocaleTimeString()}</span>
        </div>
      </div>

      <div className="relative z-10 p-4 max-w-screen-xl mx-auto">
        <div className="grid grid-cols-12 gap-4">

          {/* LEFT PANEL — Timer + Controls */}
          <div className="col-span-12 lg:col-span-4 flex flex-col gap-4">

            {/* Project Card */}
            <div className="bg-[#0a1020] border border-[#1a2540] rounded p-4">
              <div className="flex items-center justify-between mb-3">
                <span className="text-[10px] text-[#445] tracking-widest uppercase">Project</span>
                <button onClick={() => setShowProjectPanel(p => !p)}
                  className="flex items-center gap-1 text-[10px] text-[#0088ff] hover:text-[#44aaff] transition-colors border border-[#0088ff]/30 px-2 py-1 rounded">
                  <Search size={10} /> {project ? 'CHANGE' : 'SELECT'}
                </button>
              </div>
              {project ? (
                <div>
                  <div className="flex items-center gap-3 mb-3">
                    {project.owner?.image && (
                      <img src={project.owner.image} alt="" className="w-8 h-8 rounded-full border border-[#1a2540]" />
                    )}
                    <div>
                      <div className="text-white text-sm font-bold leading-tight">{project.name}</div>
                      <div className="text-[#445] text-[10px]">@{project.owner?.username}</div>
                    </div>
                  </div>
                  <div className="grid grid-cols-3 gap-2 text-center">
                    <div className="bg-[#060b18] border border-[#1a2540] rounded p-2">
                      <div className="text-[#00ff88] text-lg font-bold">{project.project_streak_days}</div>
                      <div className="text-[10px] text-[#445]">STREAK</div>
                    </div>
                    <div className="bg-[#060b18] border border-[#1a2540] rounded p-2">
                      <div className="text-[#0088ff] text-lg font-bold">{project.journals?.length || 0}</div>
                      <div className="text-[10px] text-[#445]">LOGS</div>
                    </div>
                    <div className="bg-[#060b18] border border-[#1a2540] rounded p-2">
                      <div className="text-[#ffd700] text-lg font-bold">{totalJournalHours}</div>
                      <div className="text-[10px] text-[#445]">HRS</div>
                    </div>
                  </div>
                  <div className="mt-2 flex items-center gap-2">
                    <span className="text-[10px] text-[#445]">STAGE {project.stage}</span>
                    <span className="text-[10px] text-[#445]">•</span>
                    <span className="text-[10px] text-[#ffd700]">{project.fruit?.toUpperCase()}</span>
                    <span className="text-[10px] text-[#445]">•</span>
                    <span className="text-[10px] text-[#0088ff]">LVL {project.level}</span>
                  </div>
                </div>
              ) : (
                <div className="text-[#445] text-xs text-center py-4">No project selected</div>
              )}

              {showProjectPanel && (
                <div className="mt-3 pt-3 border-t border-[#1a2540]">
                  <div className="text-[10px] text-[#445] mb-2">Enter project ID to load data</div>
                  <div className="flex gap-2">
                    <input
                      type="text"
                      placeholder="e.g. 5677"
                      value={projectIdInput}
                      onChange={e => setProjectIdInput(e.target.value)}
                      onKeyDown={e => e.key === 'Enter' && handleFetchProject()}
                      className="flex-1 bg-[#060b18] border border-[#1a2540] rounded px-3 py-2 text-white text-xs focus:outline-none focus:border-[#0088ff]"
                    />
                    <button onClick={handleFetchProject} disabled={projectLoading}
                      className="px-3 py-2 bg-[#0088ff] text-white text-xs rounded hover:bg-[#0066cc] disabled:opacity-50 transition-colors">
                      {projectLoading ? '...' : 'LOAD'}
                    </button>
                  </div>
                  {projectError && <div className="text-[#ff3366] text-[10px] mt-2">{projectError}</div>}
                </div>
              )}
            </div>

            {/* Main Timer */}
            <div className={`bg-[#0a1020] border rounded p-6 relative overflow-hidden transition-all duration-300 ${isLow && alertBlink ? 'border-[#ff003366]' : isRunning && isHigh ? 'border-[#00ff8844]' : 'border-[#1a2540]'}`}>
              {isLow && (
                <div className={`absolute top-2 right-2 flex items-center gap-1 text-[#ff0033] text-[10px] transition-opacity ${alertBlink ? 'opacity-100' : 'opacity-30'}`}>
                  <AlertTriangle size={10} /> LOW
                </div>
              )}
              <div className="text-center mb-6">
                <div className="text-[10px] text-[#445] tracking-widest mb-1">ELAPSED TIME</div>
                <div className={`text-5xl font-bold tracking-wider transition-colors duration-300 ${isHigh ? 'text-[#00ff88]' : isRunning ? 'text-[#ff3366]' : 'text-[#445]'}`}>
                  {formatTime(elapsedSeconds)}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-3 mb-6">
                <StatBox label="INCOME" value={`$${currentIncome.toFixed(4)}`} color="#00ff88"
                  sub={incomeChange !== 0 ? `${incomeChange > 0 ? '+' : ''}${incomeChange.toFixed(5)}` : null}
                  subColor={incomeChange >= 0 ? '#00ff88' : '#ff3366'} />
                <StatBox label="RATE/HR" value={`$${incomePerHour.toFixed(3)}`} color="#0088ff" />
                <StatBox label="AVG RATE" value={`$${avgProductivity.toFixed(3)}`} color="#ffd700" />
                <StatBox label="STATUS" color={isHigh ? '#00ff88' : '#ff3366'}
                  value={
                    <span className={`flex items-center gap-1 ${isHigh ? 'text-[#00ff88]' : 'text-[#ff3366]'}`}>
                      {isHigh ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
                      {isRunning ? (isHigh ? 'BULL' : 'BEAR') : 'IDLE'}
                    </span>
                  } />
              </div>

              <div className="flex gap-3 justify-center">
                <button onClick={() => setIsRunning(r => !r)}
                  className={`flex items-center gap-2 px-5 py-2.5 rounded text-sm font-bold transition-all ${isRunning ? 'bg-[#ff3366] text-white hover:bg-[#ff1a4d]' : 'bg-[#00ff88] text-black hover:bg-[#00dd77]'}`}>
                  {isRunning ? <><Pause size={16} /> PAUSE</> : <><Play size={16} /> START</>}
                </button>
                <button onClick={handleStop} disabled={elapsedSeconds === 0}
                  className="flex items-center gap-2 px-5 py-2.5 rounded text-sm font-bold border border-[#0088ff] text-[#0088ff] hover:bg-[#0088ff]/10 disabled:opacity-30 disabled:cursor-not-allowed transition-all">
                  STOP
                </button>
                <button onClick={handleReset}
                  className="p-2.5 rounded border border-[#1a2540] text-[#445] hover:text-[#666] hover:border-[#2a3550] transition-all">
                  <RotateCcw size={16} />
                </button>
              </div>

              <div className="mt-4 flex items-center justify-between">
                <div className="text-[10px] text-[#445]">MULTIPLIER: <span className="text-[#ffd700]">{effectiveStreak.toFixed(2)}x</span></div>
                <button onClick={() => setShowFormulaEditor(f => !f)}
                  className="flex items-center gap-1 text-[10px] text-[#445] hover:text-[#666] border border-[#1a2540] px-2 py-1 rounded">
                  <Edit2 size={10} /> FORMULA
                </button>
              </div>

              {showFormulaEditor && (
                <div className="mt-3 pt-3 border-t border-[#1a2540]">
                  <div className="text-[10px] text-[#445] mb-2">Rate formula — use <code className="text-[#0088ff]">streak</code> as variable</div>
                  <input type="text" value={formula} onChange={e => setFormula(e.target.value)}
                    className="w-full bg-[#060b18] border border-[#1a2540] rounded px-3 py-2 text-white text-xs focus:outline-none focus:border-[#0088ff] font-mono" />
                </div>
              )}
            </div>

            {/* Auto-save indicator */}
            <div className="bg-[#0a1020] border border-[#1a2540] rounded px-4 py-2 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Activity size={12} className={isRunning ? 'text-[#00ff88] animate-pulse' : 'text-[#1a2540]'} />
                <span className="text-[10px] text-[#445]">AUTO-RECORDING {isRunning ? 'ACTIVE' : 'PAUSED'}</span>
              </div>
              <span className="text-[10px] text-[#445]">{liveChart.length} pts</span>
            </div>
          </div>

          {/* RIGHT PANEL — Charts + Feed */}
          <div className="col-span-12 lg:col-span-8 flex flex-col gap-4">

            {/* Live Income Chart */}
            <div className="bg-[#0a1020] border border-[#1a2540] rounded p-4">
              <div className="flex items-center justify-between mb-3">
                <div className="flex items-center gap-3">
                  <span className="text-[10px] text-[#445] tracking-widest uppercase">Live Income Feed</span>
                  {isRunning && <div className="w-1.5 h-1.5 rounded-full bg-[#00ff88] animate-pulse" />}
                </div>
                <div className="flex items-center gap-4 text-[10px]">
                  <span className="text-[#00ff88]">▲ ${currentIncome.toFixed(5)}</span>
                  {liveChart.length > 1 && (
                    <span className={incomeChange >= 0 ? 'text-[#00ff88]' : 'text-[#ff3366]'}>
                      {incomeChange >= 0 ? '+' : ''}{incomeChange.toFixed(6)}
                    </span>
                  )}
                </div>
              </div>
              <ResponsiveContainer width="100%" height={180}>
                <AreaChart data={liveChart} margin={{ top: 4, right: 4, bottom: 0, left: 0 }}>
                  <defs>
                    <linearGradient id="incomeGrad" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#00ff88" stopOpacity={0.3} />
                      <stop offset="95%" stopColor="#00ff88" stopOpacity={0} />
                    </linearGradient>
                  </defs>
                  <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.03)" />
                  <XAxis dataKey="t" stroke="#1a2540" tick={{ fontSize: 9, fill: '#334' }} interval="preserveStartEnd" />
                  <YAxis stroke="#1a2540" tick={{ fontSize: 9, fill: '#334' }} width={55}
                    tickFormatter={v => `$${v.toFixed(4)}`} />
                  <Tooltip
                    contentStyle={{ backgroundColor: '#080d1a', border: '1px solid #1a2540', borderRadius: 4, fontSize: 10 }}
                    labelStyle={{ color: '#445' }}
                    formatter={(v) => [`$${v.toFixed(6)}`, 'Income']} />
                  <Area type="monotone" dataKey="income" stroke="#00ff88" strokeWidth={1.5}
                    fill="url(#incomeGrad)" dot={false} isAnimationActive={false} />
                </AreaChart>
              </ResponsiveContainer>
            </div>

            {/* Rate/Hr Chart */}
            <div className="bg-[#0a1020] border border-[#1a2540] rounded p-4">
              <div className="flex items-center justify-between mb-3">
                <span className="text-[10px] text-[#445] tracking-widest uppercase">Rate / Hour (Real-Time)</span>
                <span className="text-[10px] text-[#0088ff]">${incomePerHour.toFixed(4)}/hr</span>
              </div>
              <ResponsiveContainer width="100%" height={120}>
                <LineChart data={liveChart} margin={{ top: 4, right: 4, bottom: 0, left: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.03)" />
                  <XAxis dataKey="t" stroke="#1a2540" tick={{ fontSize: 9, fill: '#334' }} interval="preserveStartEnd" />
                  <YAxis stroke="#1a2540" tick={{ fontSize: 9, fill: '#334' }} width={55}
                    tickFormatter={v => `$${v.toFixed(3)}`} />
                  <Tooltip
                    contentStyle={{ backgroundColor: '#080d1a', border: '1px solid #1a2540', borderRadius: 4, fontSize: 10 }}
                    formatter={(v) => [`$${v.toFixed(5)}/hr`, 'Rate']} />
                  <Line type="monotone" dataKey="rate" stroke="#0088ff" strokeWidth={1.5}
                    dot={false} isAnimationActive={false} />
                </LineChart>
              </ResponsiveContainer>
            </div>

            {/* Sessions Table */}
            <div className="bg-[#0a1020] border border-[#1a2540] rounded p-4">
              <div className="flex items-center justify-between mb-3">
                <span className="text-[10px] text-[#445] tracking-widest uppercase">Session Ledger</span>
                <span className="text-[10px] text-[#445]">{sessions.length} SESSIONS</span>
              </div>
              {sessions.length === 0 ? (
                <div className="text-center py-6 text-[#334] text-xs">No sessions recorded — start tracking to populate</div>
              ) : (
                <div className="overflow-x-auto">
                  <table className="w-full text-[11px]">
                    <thead>
                      <tr className="border-b border-[#1a2540]">
                        {['DATE', 'TIME', 'PROJECT', 'DURATION', 'INCOME', 'RATE/HR', 'STREAK'].map(h => (
                          <th key={h} className="text-left p-2 text-[#334] tracking-wider font-normal">{h}</th>
                        ))}
                      </tr>
                    </thead>
                    <tbody>
                      {[...sessions].reverse().map(s => (
                        <tr key={s.id} className="border-b border-[#0d1428] hover:bg-[#0d1428] transition-colors">
                          <td className="p-2 text-[#445]">{s.timestamp}</td>
                          <td className="p-2 text-[#445]">{s.time || '—'}</td>
                          <td className="p-2 text-[#0088ff] truncate max-w-[100px]">{s.projectName || '—'}</td>
                          <td className="p-2 text-[#556]">{formatTime(s.duration)}</td>
                          <td className="p-2 text-[#00ff88] font-bold">${s.income.toFixed(4)}</td>
                          <td className="p-2 text-[#0088ff]">${s.incomePerHour.toFixed(3)}</td>
                          <td className="p-2 text-[#ffd700]">{s.streak?.toFixed(2)}x</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>

            {/* Project Journal Feed */}
            {project?.journals?.length > 0 && (
              <div className="bg-[#0a1020] border border-[#1a2540] rounded p-4">
                <div className="flex items-center justify-between mb-3">
                  <span className="text-[10px] text-[#445] tracking-widest uppercase">Project Journal Feed — {project.name}</span>
                  <span className="text-[10px] text-[#ffd700]">{totalJournalHours}h total</span>
                </div>
                <div className="space-y-2 max-h-48 overflow-y-auto pr-1">
                  {project.journals.map(j => (
                    <div key={j.id} className="flex items-center gap-3 py-2 border-b border-[#0d1428]">
                      {j.author_image && <img src={j.author_image} alt="" className="w-6 h-6 rounded-full flex-shrink-0" />}
                      <div className="flex-1 min-w-0">
                        <div className="text-[10px] text-[#445]">@{j.author_username} • {new Date(j.created_at).toLocaleDateString()}</div>
                      </div>
                      <div className="text-[#00ff88] text-xs font-bold flex-shrink-0">{j.hours}h</div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

function StatBox({ label, value, color, sub, subColor }) {
  return (
    <div className="bg-[#060b18] border border-[#1a2540] rounded p-3">
      <div className="text-[9px] tracking-widest mb-1" style={{ color: '#334' }}>{label}</div>
      <div className="text-sm font-bold" style={{ color }}>
        {value}
      </div>
      {sub && <div className="text-[9px] mt-0.5" style={{ color: subColor }}>{sub}</div>}
    </div>
  );
}

function TickerItem({ label, value, change, neutral }) {
  const isUp = change > 0;
  const isDown = change < 0;
  return (
    <div className="flex items-center gap-1.5">
      <span className="text-[#334]">{label}</span>
      <span className={`font-bold ${neutral ? 'text-white' : isUp ? 'text-[#00ff88]' : isDown ? 'text-[#ff3366]' : 'text-white'}`}>
        {value}
      </span>
      {!neutral && change !== undefined && change !== 0 && (
        isUp ? <ChevronUp size={10} className="text-[#00ff88]" /> : <ChevronDown size={10} className="text-[#ff3366]" />
      )}
    </div>
  );
}

